def unscramble(scrambled):
    A = scrambled.copy()
    i = len(A) - 1
    
    # Balikkan proses dari index terakhir ke 2
    while i >= 2:
        # A[i-1] berisi A[:i-2] di akhir list-nya
        # Kita perlu mengeluarkannya
        if isinstance(A[i-1], list) and len(A[i-1]) > 0:
            # Ambil elemen terakhir dari A[i-1] yang seharusnya adalah A[:i-2]
            last_elem = A[i-1].pop()
            
            # Kembalikan elemen yang di-pop dari A[i-2]
            # A[i-2] seharusnya memiliki elemen terakhir yang di-pop dari A[i-1]
            if isinstance(A[i-2], list):
                # Elemen terakhir A[i-2] adalah A.pop(i-1) yang perlu dikembalikan
                popped = A[i-2].pop()
                # Insert popped ke posisi yang tepat di A
                A.insert(i-1, popped)
        
        i -= 1
    
    return A

def extract_flag(unscrambled):
    flag = ''
    for item in unscrambled:
        if isinstance(item, list) and len(item) > 0:
            flag += chr(int(item[0], 16))
        else:
            flag += chr(int(item, 16))
    return flag


def main():
    unscrambled = unscramble(enc_flag)
    flag = extract_flag(unscrambled)
    print("Flag:", colored(flag,'light_green'))

if __name__ == '__main__':
    main()